<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Combat\CombatBalanceConfigurationService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\CombatBalanceRequest;use App\Models\CombatBalanceSetting;use InvalidArgumentException;
final class CombatBalanceController extends Controller{public function index(){return view('admin.content.combat-balance.index',['setting'=>CombatBalanceSetting::findOrFail(1)]);}public function update(CombatBalanceRequest $request,CombatBalanceConfigurationService $service){try{$service->update($request->user(),$request->validated());return back()->with('status','Balance de combate actualizado correctamente.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['version'=>$e->getMessage()]);}}}
